const body = $input.first().json.body || {};

const message = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
const value   = body?.entry?.[0]?.changes?.[0]?.value;

if (!message) return [];

const from = message.from;
const name = value?.contacts?.[0]?.profile?.name || ('+' + from);

const typeMap = {
  text:     () => message.text?.body || '',
  image:    () => '[Le client a envoyé une image]',
  audio:    () => '[Le client a envoyé un message vocal]',
  video:    () => '[Le client a envoyé une vidéo]',
  document: () => '[Le client a envoyé un document]',
  sticker:  () => '[Le client a envoyé un sticker]',
};
const texte = (typeMap[message.type] || (() => `[${message.type}]`))();

return [{ json: { from, name, texte } }];

const data = $input.first().json;
const reponse = data.choices?.[0]?.message?.content?.trim() || 'Bonjour ! Notre équipe vous répond très rapidement. Pour toute urgence : *+228 90 22 64 91* — *TOGOLESE*';
const from = $('Extraire message').first().json.from;
return [{ json: { from, reponse } }];
